<span class="line">logging<span class="token punctuation">.</span>basicConfig<span class="token punctuation">(</span><span class="token builtin">format</span><span class="token operator">=</span><span class="token string">&quot;%(levelname)s:%(name)s:%(message)s&quot;</span><span class="token punctuation">)</span></span>
